import React, { useState } from 'react';

function TradeForm() {
    const [trade, setTrade] = useState({
        id:0,
        stock:'MES',
        method:'Method',
        quantity:0,
        profitLoss:0
    })

    const handleStock = e => {
        setTrade({})
        console.log('Change')
    }

    const handleSubmit = e => {
        e.preventDefault()
        console.log('Submit')
    }

    return(
        <form onSubmit={handleSubmit}>
            <span>Stock</span><span className='buffer'></span>
            <span>Method</span><span className='buffer'></span>
            <span>Quantity</span><span className='buffer'></span>
            <span>P/L</span><span className='buffer'></span>

            <p className='formLabel-buffer'></p>

            <select onChange={handleChange} autoFocus>
                <option>MES</option>
            </select>
            <select onChange={handleChange}>
                <option>Bollinger</option>
                <option>--S & R--</option>
            </select >
            <input onChange={handleChange} type='number' min='1' step='1' />
            <input onChange={handleChange} type='number' step='0.25' />

            <button type='submit'>+Trade</button>
        </form>  
    )
}

export default TradeForm;
